// Сезонное ценообразование + weekend premium
const property = $json;
const month = new Date().getMonth() + 1;

// Сезонный коэффициент
let multiplier = 1.0;
if (month >= 6 && month <= 8) multiplier = 1.5;       // пик: июнь-август
else if (month === 5 || month === 9) multiplier = 1.2; // плечо: май, сентябрь
else multiplier = 0.85;                                // несезон

const basePrice = Math.round(property.base * multiplier / 100) * 100;

// Строим prices_obj: цены на 60 дней вперёд
const prices_obj = {};
const today = new Date();
for (let i = 0; i < 60; i++) {
  const d = new Date(today);
  d.setDate(today.getDate() + i);
  const dateStr = d.toISOString().split('T')[0];
  const dayOfWeek = d.getDay(); // 0=вс, 6=сб
  // Пятница и суббота +15%
  const dayPrice = (dayOfWeek === 5 || dayOfWeek === 6)
    ? Math.round(basePrice * 1.15 / 100) * 100
    : basePrice;
  prices_obj[dateStr] = dayPrice;
}

return [{ json: { ...property, prices_obj, final_price: basePrice } }];
